// Code Node 0: run_id 생성
// 입력: Schedule Trigger에서 트리거됨
// 출력: run_id를 다음 노드에 전달

const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const dateStr = `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}`;
const timeStr = `${pad(now.getHours())}${pad(now.getMinutes())}`;
const run_id = `B_${dateStr}_${timeStr}`;

return [{ json: { run_id } }];

// Merge: production_week + line_master + run_id
const productionItems = $('Read production_week').all();
const lineMasterItems = $('Read line_master').all();
const runIdItem = $('Code 0: run_id 생성').first();

const productionRows = productionItems.map(item => item.json);
const lineMaster = lineMasterItems.map(item => item.json);
const run_id = runIdItem.json.run_id;

return [{ json: { productionRows, lineMaster, run_id } }];

// Code Node 1: 데이터 검증
// 입력: Google Sheets에서 읽은 production_week + line_master (items로 전달)
// 출력: validRows + warnings + run_id

const input = items[0].json;
const productionRows = input.productionRows;
const lineMaster = input.lineMaster;
const run_id = input.run_id;

const NUMERIC_FIELDS = [
  '일일목표', '시간당생산', '시간당양품', '시간당불량', '시간당폐기', '시간당불량률(%)',
  '누적생산', '누적양품', '누적불량', '누적폐기', '누적불량률(%)',
  '달성률(%)', '예상달성률(%)', '달성갭(%p)',
  '시간당가동(분)', '시간당비가동(분)', '시간당가동률(%)', '누적가동률(%)'
];

const REQUIRED_COLUMNS = [
  '날짜', '시간', '라인ID', '라인명', '팀', '생산품목', '일일목표',
  '시간당생산', '시간당양품', '시간당불량', '시간당폐기', '시간당불량률(%)',
  '누적생산', '누적양품', '누적불량', '누적폐기', '누적불량률(%)',
  '달성률(%)', '예상달성률(%)', '달성갭(%p)',
  '시간당가동(분)', '시간당비가동(분)', '시간당가동률(%)', '누적가동률(%)',
  '이상플래그'
];

if (!productionRows || productionRows.length === 0) {
  return [{ json: { valid: false, error: '데이터가 비어 있습니다', validRows: [], warnings: [], run_id } }];
}

const firstRow = productionRows[0];
const missingCols = REQUIRED_COLUMNS.filter(col => !(col in firstRow));
if (missingCols.length > 0) {
  return [{ json: { valid: false, error: `필수 컬럼 누락: ${missingCols.join(', ')}`, validRows: [], warnings: [], run_id } }];
}

const lineMasterIds = new Set(lineMaster.map(lm => lm['라인ID']));
const validRows = [];
const warnings = [];

for (const row of productionRows) {
  const lineId = row['라인ID'];
  const hour = row['시간'];

  if (!lineId || lineId === '') {
    warnings.push({ type: 'missing_line_id', hour, message: '라인ID가 비어 있는 행 발견' });
    continue;
  }

  if (!lineMasterIds.has(lineId)) {
    warnings.push({ type: 'unknown_line', lineId, hour, message: `line_master에 없는 라인: ${lineId}` });
    continue;
  }

  const nullFields = NUMERIC_FIELDS.filter(f => {
    const val = row[f];
    return val === null || val === undefined || val === '';
  });

  if (nullFields.length > 0) {
    warnings.push({
      type: 'null_fields', lineId, hour, fields: nullFields,
      message: `${lineId} ${hour}: 빈 필드 ${nullFields.length}개`
    });
    continue;
  }

  const parsed = { ...row };
  let typeError = false;
  for (const f of NUMERIC_FIELDS) {
    const num = parseFloat(parsed[f]);
    if (isNaN(num)) {
      warnings.push({ type: 'type_error', lineId, hour, field: f, message: `${lineId} ${hour}: ${f} 값이 숫자가 아님` });
      typeError = true;
      break;
    }
    parsed[f] = num;
  }

  if (!typeError) {
    validRows.push(parsed);
  }
}

const hours = [...new Set(validRows.map(r => r['시간']))].sort();
const currentHour = hours.length > 0 ? hours[hours.length - 1] : null;
const currentRows = currentHour ? validRows.filter(r => r['시간'] === currentHour) : [];

for (const lm of lineMaster) {
  if (currentHour && !currentRows.find(r => r['라인ID'] === lm['라인ID'])) {
    warnings.push({
      type: 'missing_line', lineId: lm['라인ID'], lineName: lm['라인명'], hour: currentHour,
      message: `${lm['라인명']}(${lm['라인ID']}): ${currentHour} 데이터 없음`
    });
  }
}

return [{ json: { valid: true, validRows, warnings, run_id, lineMaster } }];

// Code Node 2: 이상 탐지 + hourly_summary 생성
// 입력: Code 1에서 전달된 validRows, lineMaster, run_id
// 출력: anomalies + hourly_summary

const input = items[0].json;
const productionRows = input.validRows;
const lineMaster = input.lineMaster;
const run_id = input.run_id;

const rules = [
  { id: "rule_01", name: "생산량 급감", type: "drop_rate", target: "시간당생산", compare_with: "previous_hour", levels: [{ severity: "심각", min: 40, max: null },{ severity: "중간", min: 20, max: 40 },{ severity: "낮음", min: 5, max: 20 }], message: "{line_name}: 생산량 {value}% 감소 (이전 {prev} → 현재 {curr})" },
  { id: "rule_02", name: "가동률 저하", type: "below_threshold", target: "시간당가동률(%)", levels: [{ severity: "심각", min: null, max: 30 },{ severity: "중간", min: 30, max: 50 },{ severity: "낮음", min: 50, max: 70 }], message: "{line_name}: 가동률 {value}% (기준 미달)" },
  { id: "rule_03", name: "불량률 급등", type: "exceeds_baseline", target: "시간당불량률(%)", baseline_field: "정상불량률", levels: [{ severity: "심각", min: 5, max: null },{ severity: "중간", min: 3, max: 5 },{ severity: "낮음", min: 2, max: 3 }], message: "{line_name}: 불량률 {value}% (정상의 {ratio}배, 기준 {baseline}%)" },
  { id: "rule_04", name: "달성률 지연", type: "below_threshold", target: "달성갭(%p)", levels: [{ severity: "심각", min: null, max: -30 },{ severity: "중간", min: -30, max: -15 },{ severity: "낮음", min: -15, max: -5 }], message: "{line_name}: 달성갭 {value}%p (예상 대비 지연)" },
  { id: "rule_05", name: "생산 정체", type: "consecutive_zero", target: "시간당생산", levels: [{ severity: "심각", min: 3, max: null },{ severity: "중간", min: 2, max: 3 },{ severity: "낮음", min: 1, max: 2 }], message: "{line_name}: 생산 {value}시간 연속 0 (설비 정지 의심)" },
  { id: "rule_06", name: "폐기 발생", type: "above_threshold", target: "시간당폐기", rate_base: "시간당생산", levels: [{ severity: "심각", min: 3, max: null },{ severity: "중간", min: 1, max: 3 },{ severity: "낮음", min: 0.1, max: 1 }], message: "{line_name}: 폐기율 {value}% ({scrap}개/{production}개)" },
  { id: "rule_07", name: "복합 이상", type: "compound", operator: "AND", conditions: [{ target: "시간당생산", compare_type: "drop_rate", compare_with: "previous_hour", levels: [{ severity: "심각", min: 30, max: null },{ severity: "중간", min: 15, max: 30 },{ severity: "낮음", min: 5, max: 15 }] },{ target: "시간당불량률(%)", compare_type: "exceeds_baseline", baseline_field: "정상불량률", levels: [{ severity: "심각", min: 3, max: null },{ severity: "중간", min: 2, max: 3 },{ severity: "낮음", min: 1.5, max: 2 }] }], message: "{line_name}: 복합 이상 — 생산 {drop}% 감소 + 불량 {ratio}배 증가" },
  { id: "rule_08", name: "가동률 급락", type: "drop_points", target: "시간당가동률(%)", compare_with: "previous_hour", levels: [{ severity: "심각", min: 50, max: null },{ severity: "중간", min: 30, max: 50 },{ severity: "낮음", min: 15, max: 30 }], message: "{line_name}: 가동률 {value}%p 급락 (이전 {prev}% → 현재 {curr}%)" }
];

// --- 유틸 함수 ---
function getLastTwoHours(rows) {
  const hours = [...new Set(rows.map(r => r['시간']))].sort();
  if (hours.length < 1) return { current: [], previous: [], currentHour: null, previousHour: null };
  const currentHour = hours[hours.length - 1];
  const previousHour = hours.length >= 2 ? hours[hours.length - 2] : null;
  return {
    current: rows.filter(r => r['시간'] === currentHour),
    previous: previousHour ? rows.filter(r => r['시간'] === previousHour) : [],
    currentHour, previousHour
  };
}

function getConsecutiveZeros(rows, lineId, targetField) {
  const lineRows = rows.filter(r => r['라인ID'] === lineId).sort((a, b) => a['시간'].localeCompare(b['시간']));
  let count = 0;
  for (let i = lineRows.length - 1; i >= 0; i--) {
    if (parseFloat(lineRows[i][targetField]) === 0) count++;
    else break;
  }
  return count;
}

function matchLevel(value, levels) {
  for (const level of levels) {
    const { min, max } = level;
    if (min === null && max === null) continue;
    if (min === null) { if (value < max) return level; }
    else if (max === null) { if (value >= min) return level; }
    else { if (value >= min && value < max) return level; }
  }
  return null;
}

function fmt(template, params) {
  let msg = template;
  for (const [key, val] of Object.entries(params)) { msg = msg.split(`{${key}}`).join(val); }
  return msg;
}

function evaluateRule(rule, row, prevRow, master, allRows, lineId) {
  if (rule.type === 'compound') {
    if (rule.operator !== 'AND') return null;
    const results = [];
    for (const cond of rule.conditions) {
      let val = null;
      if (cond.compare_type === 'drop_rate') {
        if (!prevRow) return null;
        const curr = parseFloat(row[cond.target]), prev = parseFloat(prevRow[cond.target]);
        if (isNaN(curr) || isNaN(prev) || prev === 0) return null;
        val = ((prev - curr) / prev) * 100;
        if (val <= 0) return null;
      } else if (cond.compare_type === 'exceeds_baseline') {
        const v = parseFloat(row[cond.target]), bl = parseFloat(master[cond.baseline_field]);
        if (isNaN(v) || isNaN(bl) || bl === 0) return null;
        val = v / bl;
      }
      if (val === null) return null;
      const level = matchLevel(val, cond.levels);
      if (!level) return null;
      results.push({ severity: level.severity, value: val });
    }
    if (results.length !== rule.conditions.length) return null;
    const sOrder = { '심각': 0, '중간': 1, '낮음': 2 };
    const worst = results.reduce((w, r) => sOrder[r.severity] < sOrder[w] ? r.severity : w, '낮음');
    return { severity: worst, message: fmt(rule.message, { line_name: row['라인명'], drop: results[0].value.toFixed(1), ratio: results[1].value.toFixed(1) }) };
  }

  if (rule.type === 'drop_rate') {
    if (!prevRow) return null;
    const curr = parseFloat(row[rule.target]), prev = parseFloat(prevRow[rule.target]);
    if (isNaN(curr) || isNaN(prev) || prev === 0) return null;
    const dropRate = ((prev - curr) / prev) * 100;
    if (dropRate <= 0) return null;
    const level = matchLevel(dropRate, rule.levels);
    if (!level) return null;
    return { severity: level.severity, message: fmt(rule.message, { line_name: row['라인명'], value: dropRate.toFixed(1), prev, curr }) };
  }

  if (rule.type === 'below_threshold') {
    const val = parseFloat(row[rule.target]);
    if (isNaN(val)) return null;
    const level = matchLevel(val, rule.levels);
    if (!level) return null;
    return { severity: level.severity, message: fmt(rule.message, { line_name: row['라인명'], value: val.toFixed(1) }) };
  }

  if (rule.type === 'exceeds_baseline') {
    const val = parseFloat(row[rule.target]), bl = parseFloat(master[rule.baseline_field]);
    if (isNaN(val) || isNaN(bl) || bl === 0) return null;
    const ratio = val / bl;
    const level = matchLevel(ratio, rule.levels);
    if (!level) return null;
    return { severity: level.severity, message: fmt(rule.message, { line_name: row['라인명'], value: val.toFixed(1), ratio: ratio.toFixed(1), baseline: bl.toFixed(1) }) };
  }

  if (rule.type === 'above_threshold') {
    const scrap = parseFloat(row[rule.target]), prod = parseFloat(row[rule.rate_base]);
    if (isNaN(scrap) || isNaN(prod) || prod === 0) return null;
    const rate = (scrap / prod) * 100;
    const level = matchLevel(rate, rule.levels);
    if (!level) return null;
    return { severity: level.severity, message: fmt(rule.message, { line_name: row['라인명'], value: rate.toFixed(1), scrap, production: prod }) };
  }

  if (rule.type === 'consecutive_zero') {
    const count = getConsecutiveZeros(allRows, lineId, rule.target);
    if (count === 0) return null;
    const level = matchLevel(count, rule.levels);
    if (!level) return null;
    return { severity: level.severity, message: fmt(rule.message, { line_name: row['라인명'], value: count }) };
  }

  if (rule.type === 'drop_points') {
    if (!prevRow) return null;
    const curr = parseFloat(row[rule.target]), prev = parseFloat(prevRow[rule.target]);
    if (isNaN(curr) || isNaN(prev)) return null;
    const drop = prev - curr;
    if (drop <= 0) return null;
    const level = matchLevel(drop, rule.levels);
    if (!level) return null;
    return { severity: level.severity, message: fmt(rule.message, { line_name: row['라인명'], value: drop.toFixed(1), prev: prev.toFixed(1), curr: curr.toFixed(1) }) };
  }

  return null;
}

// --- 메인 로직 ---
const { current, previous, currentHour, previousHour } = getLastTwoHours(productionRows);

if (current.length === 0) {
  return [{ json: { anomalies: [], hourly_summary: [], currentHour: null, run_id, lineMaster, warnings: input.warnings } }];
}

const lineMasterMap = {};
for (const lm of lineMaster) { lineMasterMap[lm['라인ID']] = lm; }

const anomalies = [];
for (const row of current) {
  const lineId = row['라인ID'];
  const master = lineMasterMap[lineId];
  if (!master) continue;
  const prevRow = previous.find(r => r['라인ID'] === lineId);

  for (const rule of rules) {
    try {
      const result = evaluateRule(rule, row, prevRow, master, productionRows, lineId);
      if (result) {
        anomalies.push({
          날짜: row['날짜'], 시간: currentHour, 라인ID: lineId, 라인명: row['라인명'],
          팀: row['팀'], 품목: row['생산품목'], type: rule.name, severity: result.severity,
          detail: result.message, rule_id: rule.id
        });
      }
    } catch (e) { /* 해당 룰 스킵 */ }
  }
}

// hourly_summary 생성
const teams = [...new Set(current.map(r => r['팀']))];
const date = current[0]?.['날짜'] || '';
const hourly_summary = teams.map(team => {
  const teamRows = current.filter(r => r['팀'] === team);
  const planTotal = teamRows.reduce((s, r) => s + (parseFloat(r['일일목표']) || 0), 0);
  const actualTotal = teamRows.reduce((s, r) => s + (parseFloat(r['시간당생산']) || 0), 0);
  const defectTotal = teamRows.reduce((s, r) => s + (parseFloat(r['시간당불량']) || 0), 0);
  const scrapTotal = teamRows.reduce((s, r) => s + (parseFloat(r['시간당폐기']) || 0), 0);
  const uptimeSum = teamRows.reduce((s, r) => s + (parseFloat(r['시간당가동(분)']) || 0), 0);
  const downtimeSum = teamRows.reduce((s, r) => s + (parseFloat(r['시간당비가동(분)']) || 0), 0);
  const avgUptime = teamRows.length > 0 ? (uptimeSum / (uptimeSum + downtimeSum)) * 100 : 0;
  const achieveRate = planTotal > 0 ? (actualTotal / planTotal) * 100 : 0;
  return {
    날짜: date, 시간: currentHour, 팀: team, 작업건수: teamRows.length, 계획합계: planTotal,
    실적합계: actualTotal, '달성률(%)': Math.round(achieveRate * 100) / 100, 불량합계: defectTotal,
    폐기합계: scrapTotal, '평균가동률(%)': Math.round(avgUptime * 100) / 100, '비가동합계(분)': downtimeSum
  };
});

return [{ json: { anomalies, hourly_summary, currentHour, run_id, lineMaster, warnings: input.warnings } }];

// Extract hourly_summary rows for Google Sheets append
const input = items[0].json;
const rows = input.hourly_summary || [];
if (rows.length === 0) return [{ json: { empty: true } }];
return rows.map(r => ({ json: r }));

// Merge: anomalies from Code 2 + historical anomaly_log
const anomalyData = $('Code 2: 이상 탐지').first();
const historicalItems = $('Read anomaly_log').all();

const historicalLog = historicalItems.map(item => item.json);

return [{ json: {
  anomalies: anomalyData.json.anomalies,
  historicalLog,
  run_id: anomalyData.json.run_id,
  currentHour: anomalyData.json.currentHour,
  lineMaster: anomalyData.json.lineMaster,
  warnings: anomalyData.json.warnings,
  hourly_summary: anomalyData.json.hourly_summary
} }];

// Code Node 3: 패턴 분류 + idempotency_key + 중복 알림 방지
// 입력: Code 2의 anomalies + Google Sheets에서 읽은 anomaly_log 이력
// 출력: 분류된 anomalies + notification 판정

const input = items[0].json;
const newAnomalies = input.anomalies;
const historicalLog = input.historicalLog || [];
const run_id = input.run_id;
const currentHour = input.currentHour;
const lineMaster = input.lineMaster;
const warnings = input.warnings || [];
const hourly_summary = input.hourly_summary;

if (!newAnomalies || newAnomalies.length === 0) {
  return [{ json: { classifiedAnomalies: [], run_id, currentHour, lineMaster, warnings, hourly_summary, hasSevere: false, hasMedium: false } }];
}

// --- idempotency_key 생성 + 중복 제거 ---
const existingKeys = new Set(historicalLog.filter(e => e.idempotency_key).map(e => e.idempotency_key));
const deduplicated = [];
for (const a of newAnomalies) {
  const key = `${a['라인ID']}_${a.rule_id}_${a['날짜']}_${a['시간']}`;
  a.idempotency_key = key;
  if (!existingKeys.has(key)) {
    deduplicated.push(a);
  }
}

// --- 패턴 분류 ---
const severityOrder = { '낮음': 0, '중간': 1, '심각': 2 };

const classified = deduplicated.map(anomaly => {
  const history = historicalLog.filter(h => h['라인ID'] === anomaly['라인ID'] && h['type'] === anomaly.type);
  const count = history.length;
  let patternType;

  if (count === 0) {
    patternType = '신규';
  } else if (count <= 2) {
    patternType = '반복';
    // 심각도 상승 추세 확인
    const sorted = [...history].sort((a, b) => `${a['날짜']} ${a['시간']}`.localeCompare(`${b['날짜']} ${b['시간']}`));
    if (sorted.length >= 2) {
      const levels = sorted.slice(-2).map(h => severityOrder[h.severity] || 0);
      const currentLevel = severityOrder[anomaly.severity] || 0;
      if (levels[1] > levels[0] || currentLevel > levels[1]) {
        patternType = '악화';
      }
    }
  } else {
    patternType = '악화';
  }

  let finalSeverity = anomaly.severity;
  const originalSeverity = anomaly.severity;
  if (patternType === '악화' && (anomaly.severity === '낮음' || anomaly.severity === '중간')) {
    finalSeverity = '심각';
  }

  return {
    ...anomaly,
    severity: finalSeverity,
    original_severity: originalSeverity,
    pattern_type: patternType,
    recurrence_count: count,
    run_id,
    notification_status: 'pending'
  };
});

// --- 중복 알림 방지 (Static Data) ---
const staticData = $getWorkflowStaticData('global');
const alertHistory = staticData.alertHistory || {};
const now = new Date().toISOString();

for (const a of classified) {
  const alertKey = `${a['라인ID']}_${a.type}`;
  const lastAlert = alertHistory[alertKey];

  if (a.severity === '심각') {
    if (lastAlert) {
      const elapsed = (new Date(now) - new Date(lastAlert)) / 1000 / 60;
      if (elapsed < 60) {
        a.notification_status = 'skipped';
      } else {
        alertHistory[alertKey] = now;
      }
    } else {
      alertHistory[alertKey] = now;
    }
  } else if (a.severity === '중간') {
    if (lastAlert) {
      const lastDate = lastAlert.slice(0, 13);
      const nowDate = now.slice(0, 13);
      if (lastDate === nowDate) {
        a.notification_status = 'skipped';
      } else {
        alertHistory[alertKey] = now;
      }
    } else {
      alertHistory[alertKey] = now;
    }
  } else {
    a.notification_status = 'skipped';
  }
}

staticData.alertHistory = alertHistory;

const toNotify = classified.filter(a => a.notification_status === 'pending');
const hasSevere = toNotify.some(a => a.severity === '심각' || a.pattern_type === '악화');
const hasMedium = toNotify.some(a => a.severity === '중간');

return [{ json: {
  classifiedAnomalies: classified,
  toNotify,
  run_id, currentHour, lineMaster, warnings, hourly_summary,
  hasSevere, hasMedium
} }];

// Extract classified anomaly rows for append
const input = items[0].json;
const rows = input.classifiedAnomalies || [];
if (rows.length === 0) return [{ json: { empty: true } }];
return rows.map(r => ({ json: r }));

// Code Node 4: 마스킹 + Claude API 프롬프트 조합
// 입력: 심각/악화 이상 목록 + lineMaster
// 출력: 마스킹된 프롬프트 + maskDict (언마스킹용)

const input = items[0].json;
const toNotify = input.toNotify;
const lineMaster = input.lineMaster;
const run_id = input.run_id;
const warnings = input.warnings || [];
const hourly_summary = input.hourly_summary;
const classifiedAnomalies = input.classifiedAnomalies;

// 심각 또는 악화 건만 AI 분석 대상
const aiTargets = toNotify
  .filter(a => a.severity === '심각' || a.pattern_type === '악화')
  .sort((a, b) => {
    const sOrder = { '심각': 0, '중간': 1, '낮음': 2 };
    const pOrder = { '악화': 0, '반복': 1, '신규': 2 };
    if (sOrder[a.severity] !== sOrder[b.severity]) return sOrder[a.severity] - sOrder[b.severity];
    return (pOrder[a.pattern_type] || 2) - (pOrder[b.pattern_type] || 2);
  })
  .slice(0, 5);

if (aiTargets.length === 0) {
  return [{ json: { skipAI: true, toNotify, classifiedAnomalies, run_id, warnings, hourly_summary, lineMaster } }];
}

// --- 마스킹 사전 생성 ---
const maskDict = {};
const reverseDict = {};
lineMaster.forEach((lm, i) => {
  const lineCode = `LINE_${String.fromCharCode(65 + i)}`;
  const productCode = `PROD_${String(i + 1).padStart(2, '0')}`;
  const teamCode = `TEAM_${lm['팀'].replace(/[^0-9]/g, '')}`;
  maskDict[lm['라인명']] = lineCode;
  maskDict[lm['품목']] = productCode;
  maskDict[lm['팀']] = teamCode;
  reverseDict[lineCode] = lm['라인명'];
  reverseDict[productCode] = lm['품목'];
  reverseDict[teamCode] = lm['팀'];
});

function applyMask(text) {
  let masked = text;
  const sortedKeys = Object.keys(maskDict).sort((a, b) => b.length - a.length);
  for (const original of sortedKeys) { masked = masked.split(original).join(maskDict[original]); }
  return masked;
}

// --- 마스킹된 이상 목록 ---
const maskedTargets = aiTargets.map((a, idx) => ({
  id: idx + 1,
  line: maskDict[a['라인명']] || a['라인명'],
  product: maskDict[a['품목']] || a['품목'],
  type: a.type,
  severity: a.severity,
  pattern: a.pattern_type,
  recurrence: a.recurrence_count,
  detail: applyMask(a.detail)
}));

// --- Claude API 프롬프트 ---
const systemPrompt = `당신은 제조 현장 이상 탐지 분석 전문가입니다.
다음 이상 건들을 분석하고 JSON 형식으로 응답해주세요.
응답에서 반드시 제공된 코드(LINE_A, PROD_01 등)를 사용하세요.
실제 이름은 사용하지 마세요.

출력 형식:
{
  "anomalies": [
    {
      "id": 번호,
      "summary": "한 줄 요약",
      "root_cause": "추정 원인",
      "action": "권장 조치",
      "pattern_verification": "동의" 또는 "보정: 이유",
      "cross_impact": "다른 라인에 미치는 영향 (없으면 '없음')"
    }
  ],
  "overall_assessment": "전체 상황 종합 평가"
}`;

const userPrompt = `다음 ${maskedTargets.length}건의 이상을 분석해주세요:\n\n${JSON.stringify(maskedTargets, null, 2)}`;

const requestBody = {
  model: "claude-sonnet-4-20250514",
  max_tokens: 2000,
  system: systemPrompt,
  messages: [{ role: "user", content: userPrompt }]
};

return [{ json: {
  skipAI: false,
  requestBody,
  reverseDict,
  aiTargets,
  toNotify,
  classifiedAnomalies,
  run_id, warnings, hourly_summary, lineMaster
} }];

// Merge Claude API response with Code 4 data
const code4Data = $('Code 4: 마스킹 + 프롬프트').first();
const apiResponse = $('HTTP Request: Claude API').first();

return [{ json: {
  ...code4Data.json,
  apiResponse: apiResponse.json
} }];

// Code Node 5: AI 응답 파싱 + 언마스킹 + 이메일 본문 생성
// 입력: Claude API 응답 + reverseDict + 이상 목록
// 출력: anomaly_log 업데이트 데이터 + 이메일 본문

const input = items[0].json;
const reverseDict = input.reverseDict || {};
const aiTargets = input.aiTargets || [];
const toNotify = input.toNotify || [];
const classifiedAnomalies = input.classifiedAnomalies || [];
const run_id = input.run_id;
const warnings = input.warnings || [];
const skipAI = input.skipAI || false;

// --- 언마스킹 함수 ---
function applyUnmask(text) {
  let unmasked = text;
  const sortedKeys = Object.keys(reverseDict).sort((a, b) => b.length - a.length);
  for (const code of sortedKeys) { unmasked = unmasked.split(code).join(reverseDict[code]); }
  return unmasked;
}

// --- AI 응답 파싱 ---
let aiResult = null;
let aiParsed = false;

if (!skipAI && input.apiResponse) {
  const rawText = input.apiResponse.content?.[0]?.text || '';
  try {
    const jsonMatch = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '');
    aiResult = JSON.parse(jsonMatch);
    aiParsed = true;
  } catch (e) {
    aiResult = { raw_text: rawText };
    aiParsed = false;
  }
}

// --- anomaly_log에 AI 해석 반영 ---
for (const a of classifiedAnomalies) {
  if (aiParsed && aiResult?.anomalies) {
    const targetIdx = aiTargets.findIndex(t => t['라인ID'] === a['라인ID'] && t.type === a.type);
    if (targetIdx >= 0) {
      const aiEntry = aiResult.anomalies.find(e => e.id === targetIdx + 1);
      if (aiEntry) {
        const insight = [
          aiEntry.summary,
          `원인: ${aiEntry.root_cause}`,
          `조치: ${aiEntry.action}`,
          `패턴검증: ${aiEntry.pattern_verification}`,
          aiEntry.cross_impact !== '없음' ? `교차영향: ${aiEntry.cross_impact}` : ''
        ].filter(Boolean).join(' | ');
        a.ai_insight = applyUnmask(insight);
        a.ai_parsed = true;
      }
    }
  } else if (!skipAI && !aiParsed && aiResult?.raw_text) {
    const targetIdx = aiTargets.findIndex(t => t['라인ID'] === a['라인ID'] && t.type === a.type);
    if (targetIdx >= 0) {
      a.ai_insight = applyUnmask(aiResult.raw_text);
      a.ai_parsed = false;
    }
  }

  if (!a.ai_insight) {
    a.ai_insight = '';
    a.ai_parsed = false;
  }
}

// --- 이메일 본문 생성 ---
const severeList = toNotify.filter(a => a.severity === '심각');
const mediumList = toNotify.filter(a => a.severity === '중간');
const lowList = classifiedAnomalies.filter(a => a.severity === '낮음');

let emailSubject = '';
let emailBody = '';

if (severeList.length > 0 || mediumList.length > 0) {
  emailSubject = `[생산 이상 알림] ${severeList.length > 0 ? '🔴 심각 ' + severeList.length + '건' : ''}${mediumList.length > 0 ? ' 🟡 중간 ' + mediumList.length + '건' : ''} (${run_id})`;

  const parts = [];

  if (warnings.length > 0) {
    parts.push('<h3>⚠️ 데이터 경고</h3>');
    parts.push('<ul>' + warnings.map(w => `<li>${w.message}</li>`).join('') + '</ul>');
    parts.push('<hr>');
  }

  if (severeList.length > 0) {
    parts.push('<h3>🔴 심각</h3>');
    for (const a of severeList) {
      const matched = classifiedAnomalies.find(c => c.idempotency_key === a.idempotency_key);
      parts.push(`<div style="margin-bottom:12px;padding:10px;border-left:4px solid #e74c3c;background:#fdf2f2;">`);
      parts.push(`<b>${a['라인명']} — ${a.type}</b> (${a.pattern_type}, ${a.recurrence_count}회 발생)<br>`);
      parts.push(`${a.detail}<br>`);
      if (matched?.ai_insight) {
        parts.push(`<br><b>AI 분석:</b> ${matched.ai_insight}`);
      }
      parts.push(`</div>`);
    }
  }

  if (mediumList.length > 0) {
    parts.push('<h3>🟡 중간</h3>');
    for (const a of mediumList) {
      parts.push(`<div style="margin-bottom:8px;padding:8px;border-left:4px solid #f39c12;background:#fef9e7;">`);
      parts.push(`<b>${a['라인명']} — ${a.type}</b> (${a.pattern_type})<br>${a.detail}`);
      parts.push(`</div>`);
    }
  }

  if (lowList.length > 0) {
    parts.push('<h3>ℹ️ 참고 (낮음)</h3>');
    parts.push('<ul>' + lowList.map(a => `<li>${a['라인명']}: ${a.type} — ${a.detail}</li>`).join('') + '</ul>');
  }

  parts.push(`<hr><p style="color:#888;font-size:12px;">run_id: ${run_id} | 생성 시각: ${new Date().toISOString()}</p>`);
  emailBody = parts.join('\n');
}

// --- anomaly_log 저장용 행 변환 ---
const anomalyLogRows = classifiedAnomalies.map(a => ({
  날짜: a['날짜'],
  시간: a['시간'],
  라인ID: a['라인ID'],
  라인명: a['라인명'],
  팀: a['팀'],
  품목: a['품목'],
  type: a.type,
  severity: a.severity,
  detail: a.detail,
  pattern_type: a.pattern_type,
  recurrence_count: a.recurrence_count,
  ai_insight: a.ai_insight || '',
  ai_parsed: a.ai_parsed || false,
  run_id: a.run_id,
  idempotency_key: a.idempotency_key,
  notification_status: a.notification_status
}));

return [{ json: {
  anomalyLogRows,
  emailSubject,
  emailBody,
  sendEmail: (severeList.length > 0 || mediumList.length > 0),
  hasSevere: severeList.length > 0,
  run_id
} }];

// Code 5 (skipAI mode): 이메일 생성 without AI analysis
const input = items[0].json;
const toNotify = input.toNotify || [];
const classifiedAnomalies = input.classifiedAnomalies || [];
const run_id = input.run_id;
const warnings = input.warnings || [];

const mediumList = toNotify.filter(a => a.severity === '중간');
const lowList = classifiedAnomalies.filter(a => a.severity === '낮음');

let emailSubject = '';
let emailBody = '';

if (mediumList.length > 0) {
  emailSubject = '[생산 이상 알림] 🟡 중간 ' + mediumList.length + '건 (' + run_id + ')';

  const parts = [];

  if (warnings.length > 0) {
    parts.push('<h3>⚠️ 데이터 경고</h3>');
    parts.push('<ul>' + warnings.map(w => '<li>' + w.message + '</li>').join('') + '</ul>');
    parts.push('<hr>');
  }

  parts.push('<h3>🟡 중간</h3>');
  for (const a of mediumList) {
    parts.push('<div style="margin-bottom:8px;padding:8px;border-left:4px solid #f39c12;background:#fef9e7;">');
    parts.push('<b>' + a['라인명'] + ' — ' + a.type + '</b> (' + a.pattern_type + ')<br>' + a.detail);
    parts.push('</div>');
  }

  if (lowList.length > 0) {
    parts.push('<h3>ℹ️ 참고 (낮음)</h3>');
    parts.push('<ul>' + lowList.map(a => '<li>' + a['라인명'] + ': ' + a.type + ' — ' + a.detail + '</li>').join('') + '</ul>');
  }

  parts.push('<hr><p style="color:#888;font-size:12px;">run_id: ' + run_id + ' | 생성 시각: ' + new Date().toISOString() + '</p>');
  emailBody = parts.join('\n');
}

const anomalyLogRows = classifiedAnomalies.map(a => ({
  '날짜': a['날짜'], '시간': a['시간'], '라인ID': a['라인ID'], '라인명': a['라인명'],
  '팀': a['팀'], '품목': a['품목'], type: a.type, severity: a.severity,
  detail: a.detail, pattern_type: a.pattern_type, recurrence_count: a.recurrence_count,
  ai_insight: '', ai_parsed: false, run_id: a.run_id,
  idempotency_key: a.idempotency_key, notification_status: a.notification_status
}));

return [{ json: {
  anomalyLogRows,
  emailSubject,
  emailBody,
  sendEmail: mediumList.length > 0,
  hasSevere: false,
  run_id
} }];
